patch:
--- a/counter_32bit.sv
+++ b/counter_32bit.sv
@@ -1,12 +1,12 @@
 module counter_32bit(
     input clk,
     input rst_n,
     input [31:0] load_val,
     input load_en,
     output reg [31:0] count
 );

-    always @(posedge clk) begin
+    always @(posedge clk or negedge rst_n) begin
         if (!rst_n)
             count <= 32'h0;
         else if (load_en)
             count <= load_val;
         else
             count <= count + 1;

before_code:
module counter_32bit(
    input clk,
    input rst_n,
    input [31:0] load_val,
    input load_en,
    output reg [31:0] count
 );

    always @(posedge clk) begin
        if (!rst_n)
            count <= 32'h0;
        else if (load_en)
            count <= load_val;
        else
            count <= count + 1;
    end

endmodule

after_code:
module counter_32bit(
    input clk,
    input rst_n,
    input [31:0] load_val,
    input load_en,
    output reg [31:0] count
 );

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            count <= 32'h0;
        else if (load_en)
            count <= load_val;
        else
            count <= count + 1;
    end

endmodule
